/*
 * Lightweight local chessboard.js 1.x-compatible implementation.
 * Implements the API and callbacks used by this project without network access.
 */
;(function (global) {
  'use strict';

  var FILES = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];
  var START_FEN = 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR';

  function isFunction(value) { return typeof value === 'function'; }

  function fenToPosition(fen) {
    if (!fen || typeof fen !== 'string') return {};
    fen = fen === 'start' ? START_FEN : fen.split(/\s+/)[0];
    var rows = fen.split('/');
    if (rows.length !== 8) return {};
    var position = {};
    for (var row = 0; row < 8; row++) {
      var fileIndex = 0;
      for (var i = 0; i < rows[row].length; i++) {
        var token = rows[row].charAt(i);
        if (/^[1-8]$/.test(token)) {
          fileIndex += Number(token);
          continue;
        }
        if (fileIndex > 7 || !/^[prnbqkPRNBQK]$/.test(token)) return {};
        var color = token === token.toUpperCase() ? 'w' : 'b';
        var piece = token.toUpperCase();
        position[FILES[fileIndex] + (8 - row)] = color + piece;
        fileIndex++;
      }
      if (fileIndex !== 8) return {};
    }
    return position;
  }

  function clonePosition(position) {
    var copy = {};
    Object.keys(position || {}).forEach(function (square) { copy[square] = position[square]; });
    return copy;
  }

  function normalizePosition(value) {
    if (value === 'start') return fenToPosition(START_FEN);
    if (typeof value === 'string') return fenToPosition(value);
    return clonePosition(value || {});
  }

  function Chessboard(containerOrId, config) {
    var container = typeof containerOrId === 'string'
      ? document.getElementById(containerOrId)
      : containerOrId;
    if (!container) throw new Error('Chessboard container not found.');

    config = config || {};
    var orientation = config.orientation === 'black' ? 'black' : 'white';
    var showNotation = config.showNotation !== false;
    var position = normalizePosition(config.position || 'start');
    var dragSource = null;

    container.classList.add('chessboard-63f37', 'clearfix-7da63');

    function pieceUrl(piece) {
      var theme = config.pieceTheme || 'img/chesspieces/wikipedia/{piece}.png';
      if (isFunction(theme)) return theme(piece);
      return String(theme).replace('{piece}', piece);
    }

    function squareOrder() {
      var files = orientation === 'white' ? FILES.slice() : FILES.slice().reverse();
      var ranks = orientation === 'white'
        ? [8, 7, 6, 5, 4, 3, 2, 1]
        : [1, 2, 3, 4, 5, 6, 7, 8];
      var order = [];
      ranks.forEach(function (rank) {
        files.forEach(function (file) { order.push(file + rank); });
      });
      return order;
    }

    function isWhiteSquare(square) {
      return (FILES.indexOf(square.charAt(0)) + Number(square.charAt(1))) % 2 === 0;
    }

    function addNotation(squareElement, square) {
      var file = square.charAt(0);
      var rank = square.charAt(1);
      var leftFile = orientation === 'white' ? 'a' : 'h';
      var bottomRank = orientation === 'white' ? '1' : '8';
      if (file === leftFile) {
        var numeric = document.createElement('span');
        numeric.className = 'notation-322f9 numeric-fc462';
        numeric.textContent = rank;
        squareElement.appendChild(numeric);
      }
      if (rank === bottomRank) {
        var alpha = document.createElement('span');
        alpha.className = 'notation-322f9 alpha-d2270';
        alpha.textContent = file;
        squareElement.appendChild(alpha);
      }
    }

    function render() {
      container.textContent = '';
      var board = document.createElement('div');
      board.className = 'board-b72b1';

      squareOrder().forEach(function (square) {
        var squareElement = document.createElement('div');
        var piece = position[square] || null;
        squareElement.className = 'square-55d63 square-' + square + ' ' +
          (isWhiteSquare(square) ? 'white-1e1d7' : 'black-3c85d');
        squareElement.setAttribute('data-square', square);

        squareElement.addEventListener('mouseenter', function () {
          if (isFunction(config.onMouseoverSquare)) config.onMouseoverSquare(square, piece);
        });
        squareElement.addEventListener('mouseleave', function () {
          if (isFunction(config.onMouseoutSquare)) config.onMouseoutSquare(square, piece);
          squareElement.classList.remove('drag-over-local');
        });
        squareElement.addEventListener('dragover', function (event) {
          if (!dragSource) return;
          event.preventDefault();
          squareElement.classList.add('drag-over-local');
        });
        squareElement.addEventListener('dragleave', function () {
          squareElement.classList.remove('drag-over-local');
        });
        squareElement.addEventListener('drop', function (event) {
          event.preventDefault();
          squareElement.classList.remove('drag-over-local');
          if (!dragSource) return;
          var source = dragSource;
          dragSource = null;
          var result = isFunction(config.onDrop) ? config.onDrop(source, square, position[source], position[square]) : undefined;
          if (result === 'snapback' || result === false) {
            render();
            return;
          }
          position[square] = position[source];
          delete position[source];
          render();
          if (isFunction(config.onSnapEnd)) window.setTimeout(config.onSnapEnd, 0);
        });

        if (piece) {
          var image = document.createElement('img');
          image.className = 'piece-417db';
          image.src = pieceUrl(piece);
          image.alt = piece;
          image.draggable = config.draggable !== false;
          image.setAttribute('data-piece', piece);
          image.addEventListener('dragstart', function (event) {
            var allowed = !isFunction(config.onDragStart) || config.onDragStart(square, piece, position, orientation) !== false;
            if (!allowed) {
              event.preventDefault();
              return;
            }
            dragSource = square;
            if (event.dataTransfer) {
              event.dataTransfer.effectAllowed = 'move';
              event.dataTransfer.setData('text/plain', square);
            }
          });
          image.addEventListener('dragend', function () {
            dragSource = null;
            var highlighted = container.querySelectorAll('.drag-over-local');
            for (var i = 0; i < highlighted.length; i++) highlighted[i].classList.remove('drag-over-local');
          });
          squareElement.appendChild(image);
        }

        if (showNotation) addNotation(squareElement, square);
        board.appendChild(squareElement);
      });

      container.appendChild(board);
    }

    var api = {
      position: function (nextPosition) {
        if (arguments.length === 0) return clonePosition(position);
        position = normalizePosition(nextPosition);
        render();
        return api;
      },
      clear: function () { position = {}; render(); return api; },
      start: function () { position = fenToPosition(START_FEN); render(); return api; },
      orientation: function (nextOrientation) {
        if (!nextOrientation) return orientation;
        if (nextOrientation === 'flip') orientation = orientation === 'white' ? 'black' : 'white';
        else if (nextOrientation === 'white' || nextOrientation === 'black') orientation = nextOrientation;
        render();
        return api;
      },
      resize: function () { return api; },
      destroy: function () { container.textContent = ''; container.classList.remove('chessboard-63f37', 'clearfix-7da63'); }
    };

    render();
    return api;
  }

  Chessboard.fenToObj = fenToPosition;
  Chessboard.objToFen = function (position) {
    var rows = [];
    for (var rank = 8; rank >= 1; rank--) {
      var row = '';
      var empty = 0;
      for (var file = 0; file < 8; file++) {
        var piece = position[FILES[file] + rank];
        if (!piece) { empty++; continue; }
        if (empty) { row += empty; empty = 0; }
        var token = piece.charAt(1);
        row += piece.charAt(0) === 'w' ? token : token.toLowerCase();
      }
      if (empty) row += empty;
      rows.push(row);
    }
    return rows.join('/');
  };

  global.Chessboard = Chessboard;
})(window);
